const items = $input.all();

return [
  {
    json: {
      status: "All SAP Products Updated Successfully",
      totalProductsUpdated: items.length,
      completedAt: new Date().toISOString()
    }
  }
];

// SAP API returns data inside 'value' array
const response = $input.first().json;
const products = response.value;

// Map each product into a clean n8n item
return products.map(product => ({
  json: {
    ProductID: product.Product,
    ProductType: product.ProductType,
    BaseUnit: product.BaseUnit,
    ProductGroup: product.ProductGroup,
    CreationDate: product.CreationDate,
    LastChangeDate: product.LastChangeDate
  }
}));

// Get the full response item
const item = $input.first();

// Headers are inside item.json.headers
const headers = item.json.headers;

console.log("All headers:", JSON.stringify(headers));

// Extract CSRF Token
const csrfToken = headers['x-csrf-token'] || 
                  headers['X-CSRF-Token'] || '';

// Extract Cookies
const cookieArray = headers['set-cookie'] || [];
const cookie = Array.isArray(cookieArray) ? 
               cookieArray.join(';') : cookieArray;

console.log("CSRF Token found:", csrfToken);
console.log("Cookie found:", cookie);

// Get Product data from Loop Over Items node
const product = $('Loop Over Items').first().json;

return [
  {
    json: {
      csrfToken: csrfToken,
      cookie: cookie,
      ProductID: product.ProductID,
      ProductType: product.ProductType,
      BaseUnit: product.BaseUnit,
      ProductGroup: product.ProductGroup
    }
  }
];
